  ('promotion-6e2f88c7-moex-00165', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '民間團體或個人受託行使公權力所生之法律關係，下列敘述何者錯誤？', '["於受委託之範圍以外，非為行政機關", "於受委託之範圍以外與第三人發生法律關係者，應屬公法關係", "受委託行使公權力之團體，其執行職務之人，視同委託機關之公務員", "於受委託之範圍內，應以該私人或團體的名義作成行政處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
