  ('promotion-6e2f88c7-moex-00167', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '行政機關執行職務時，下列有關請求無隸屬關係之其他機關協助的敘述，何者有誤？', '["行政機關因人員、設備不足等事實上原因時，得請求其他機關協助", "對於請求其他機關協助，原則上應以書面為之", "被請求機關得以請求協助之行為，非其權限範圍為由拒絕之", "被請求機關若經請求機關之共同上級機關協調，不得向請求協助機關要求負擔行政協助所需費用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
